#!/usr/bin/env bash
source <(curl -fsSL https://raw.githubusercontent.com/community-scripts/ProxmoxVE/main/misc/install.func)
# Copyright (c) 2021-2026 community-scripts ORG
# Author: rpoltera
# License: MIT
# Source: https://github.com/rpoltera/streamforge

# ── Handle update mode ────────────────────────────────────────────────────────
if [[ "${1:-}" == "update" ]]; then
  [[ ! -d /opt/streamforge ]] && echo "No StreamForge found" && exit 1
  systemctl stop streamforge 2>/dev/null || true
  pkill -9 -f ffmpeg 2>/dev/null || true
  printf '%s' '' | base64 -d > "/opt/streamforge/server/index.js"
  printf '%s' '' | base64 -d > "/opt/streamforge/server/package.json"
  printf '%s' '' | base64 -d > "/opt/streamforge/public/index.html"
  printf '%s' '' | base64 -d > "/opt/streamforge/public/css/main.css"
  printf '%s' '' | base64 -d > "/opt/streamforge/public/js/app.js"
  chown -R streamforge:streamforge /opt/streamforge
  su -s /bin/bash streamforge -c "cd /opt/streamforge/server && npm install --production --quiet"
  systemctl start streamforge
  sleep 2 && systemctl is-active --quiet streamforge && echo "Updated OK" || echo "Failed"
  exit 0
fi

# ── Fresh install ─────────────────────────────────────────────────────────────
setting_up_container
network_check
update_os

msg_info "Installing Dependencies"
$STD apt-get install -y curl wget ffmpeg nginx
msg_ok "Installed Dependencies"

msg_info "Installing Node.js 20"
$STD bash <(curl -fsSL https://deb.nodesource.com/setup_20.x)
$STD apt-get install -y nodejs
msg_ok "Installed Node.js $(node --version)"

msg_info "Setting Up StreamForge"
useradd -r -s /bin/false -d /opt/streamforge streamforge 2>/dev/null || true
mkdir -p /opt/streamforge/server /opt/streamforge/public/css /opt/streamforge/public/js
mkdir -p /var/lib/streamforge/config /var/lib/streamforge/hls /var/lib/streamforge/uploads

printf '%s' '' | base64 -d > "/opt/streamforge/server/index.js"
printf '%s' '' | base64 -d > "/opt/streamforge/server/package.json"
printf '%s' '' | base64 -d > "/opt/streamforge/public/index.html"
printf '%s' '' | base64 -d > "/opt/streamforge/public/css/main.css"
printf '%s' '' | base64 -d > "/opt/streamforge/public/js/app.js"

cd /opt/streamforge/server && $STD npm install --production
chown -R streamforge:streamforge /opt/streamforge /var/lib/streamforge
chmod -R 755 /opt/streamforge /var/lib/streamforge
msg_ok "StreamForge Set Up"

msg_info "Configuring Nginx"
cat > /etc/nginx/sites-available/streamforge << 'NGINX'
server {
    listen 80;
    server_name _;
    client_max_body_size 200M;
    location / {
        proxy_pass http://127.0.0.1:8080;
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection 'upgrade';
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_cache_bypass $http_upgrade;
        proxy_read_timeout 300s;
        proxy_connect_timeout 300s;
    }
}
NGINX
ln -sf /etc/nginx/sites-available/streamforge /etc/nginx/sites-enabled/
rm -f /etc/nginx/sites-enabled/default
$STD nginx -t && systemctl reload nginx
msg_ok "Configured Nginx"

msg_info "Creating Service"
cat > /etc/systemd/system/streamforge.service << 'SERVICE'
[Unit]
Description=StreamForge IPTV Playout Manager
After=network.target
Documentation=https://github.com/rpoltera/streamforge

[Service]
Type=simple
User=streamforge
WorkingDirectory=/opt/streamforge/server
ExecStart=/usr/bin/node /opt/streamforge/server/index.js
Restart=on-failure
RestartSec=10
StandardOutput=journal
StandardError=journal
SyslogIdentifier=streamforge
Environment=SF_DATA=/var/lib/streamforge
Environment=SF_CONFIG=/var/lib/streamforge/config/config.json
Environment=SF_LOG=/var/lib/streamforge

[Install]
WantedBy=multi-user.target
SERVICE
systemctl daemon-reload
$STD systemctl enable --now streamforge
msg_ok "Created Service"

printf '#!/bin/bash\nbash <(curl -fsSL https://raw.githubusercontent.com/rpoltera/streamforge/main/streamforge-install.sh) update\n' > /usr/local/bin/streamforge-update
chmod +x /usr/local/bin/streamforge-update

motd_ssh
customize
